request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?msg ?msgName ?msgType ?model ?modelName ?origId WHERE {
  ?msg a ?msgType ;
       bbo:name ?msgName .
  FILTER(CONTAINS(LCASE(STR(?msgName)), LCASE("Transportation provisioning")))

  OPTIONAL {
    ?mf a bboExt:MessageFlow ;
        bboExt:messageRef ?ref .
    FILTER(STRENDS(STR(?msg), ?ref))
  }
  OPTIONAL {
    ?defs tai:belongsTo ?model .
    ?msg tai:belongsTo ?choreoOrDefs .
    ?choreoOrDefs tai:belongsTo ?defs .
  }

  OPTIONAL {
    ?model bbo:name ?modelName .
    OPTIONAL { ?model tai:originalId ?origId . }
  }
}
LIMIT 25
